$(document).ready(function () {
    $('#itemTitle').change(function () {
        var itemId = $(this).val();
        if (itemId) {
            // Append itemId directly to the base URL
            var url = getItemDetailsUrl + '/' + itemId;
            $.ajax({
                url: url,
                type: 'GET',
                success: function (data) {
                    $('#rate').val(data.purchase);
                    $('#gramage').val(data.gramage);
                },
                error: function (xhr) {
                    console.error("Error fetching details: " + xhr.responseText);
                }
            });
        } else {
            $('#rate').val('');
            $('#gramage').val('');
        }
    });

    $('#addEntryButton').click(function() {
        $('#itemTitle').val('');
        $('#rate').val('');
        $('#gramage').val('');
    });
});
